class Solution:
    def findValidElements(self, nums):
        n = len(nums)
        result = []
        for i in range(n):
            left = nums[:i]
            right = nums[i + 1:]
            left_ok = (not left) or nums[i] > max(left)
            right_ok = (not right) or nums[i] > max(right)
            if left_ok or right_ok:
                result.append(nums[i])
        return result

