class Solution:
    def findValidElements(self, nums: list[int]) -> list[int]:
        n = len(nums)
        prefix_max = [float('-inf')] * n
        suffix_max = [float('-inf')] * n
        running = float('-inf')
        for i in range(n):
            prefix_max[i] = running
            running = max(running, nums[i])
        running = float('-inf')
        for i in range(n - 1, -1, -1):
            suffix_max[i] = running
            running = max(running, nums[i])
        result = []
        for i in range(n):
            if nums[i] > prefix_max[i] or nums[i] > suffix_max[i]:
                result.append(nums[i])
        return result

