var findValidElements = function(nums) {
    const n = nums.length;
    const prefixMax = new Array(n).fill(-Infinity);
    const suffixMax = new Array(n).fill(-Infinity);
    let running = -Infinity;
    for (let i = 0; i < n; i++) {
        prefixMax[i] = running;
        running = Math.max(running, nums[i]);
    }
    running = -Infinity;
    for (let i = n - 1; i >= 0; i--) {
        suffixMax[i] = running;
        running = Math.max(running, nums[i]);
    }
    const result = [];
    for (let i = 0; i < n; i++) {
        if (nums[i] > prefixMax[i] || nums[i] > suffixMax[i]) {
            result.push(nums[i]);
        }
    }
    return result;
};
